const items = [
  { icon: <IconCall />, text: 'Higher outbound contact rates' },
  { icon: <IconUsers />, text: 'More qualified leads' },
  { icon: <IconChat />, text: 'More booked meetings' },
  { icon: <IconDatabase />, text: 'Less manual dialing and agent workload' },
];

export const Results = () => {
  return (
    <section className={st.layout}>
      <motion.h2
        variants={blurInUp}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true }}
      >
        Results Teams See
      </motion.h2>

      <div className={st.grid}>
        {items.map((item) => (
          <motion.div
            key={item.text}
            className={st.card}
            variants={blurInUp}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true }}
          >
            <div className={st.iconWrap}>{item.icon}</div>
            <p>{item.text}</p>
          </motion.div>
        ))}
      </div>
    </section>
  );
};
